# # Generated by create-crm-factory.ps1
Set-StrictMode -Version Latest

function New-ActionsArtifact {

    param(
        [string]$Module
    )

    Write-TextFile `
        -Path (Get-ModuleFile $Module "Actions") `
        -Content @(
"'use server';",
"",
"import { ${Module}ServiceInstance } from '@/services/crm/${Module}Service';",
"",
"export async function getAll() {",
"    return ${Module}ServiceInstance.getAll();",
"}",
"",
"export async function getById() {",
"    return ${Module}ServiceInstance.getById();",
"}",
"",
"export async function create() {",
"    return { success: true };",
"}",
"",
"export async function update() {",
"    return { success: true };",
"}",
"",
"export async function remove() {",
"    return { success: true };",
"}"
)

    Write-Success "Server Actions Generated"

}

function New-ApiRouteArtifact {

