function New-ApiArtifacts {

    param(
        [string]$Module
    )

    Write-Section "Generating API Layer"

    New-ActionsArtifact $Module

    New-ApiRouteArtifact $Module

    New-ApiItemRouteArtifact $Module

    New-DocumentationArtifact $Module

    New-TestArtifact $Module

    Write-Success "API Layer Complete"

}